//! Tests for the pipeline derive macros and declarative capability macros.
//!
//! Exercises the code generated by `#[derive(PipelineEnv)]`,
//! `#[derive(PipelineState)]`, `define_env_capabilities!`, and
//! `define_state_capabilities!` using the concrete types from `pipelines.rs`.

use std::sync::Arc;

use compiler::{
    HasInput, HasJson, HasOntology, HasSecurityCtx, Input, LocalEnv, QueryError, QueryState, Seal,
    SealInput, SealJson, SealNode, SecureEnv, SecurityContext,
};
use ontology::Ontology;

use super::setup::test_ctx;

fn env() -> SecureEnv {
    SecureEnv::new(Arc::new(Ontology::new()), test_ctx())
}

// ═════════════════════════════════════════════════════════════════════════════
// PipelineEnv derive — HasX trait impls + new() constructor
// ═════════════════════════════════════════════════════════════════════════════

#[test]
fn secure_env_new_stores_fields() {
    let ontology = Arc::new(Ontology::new());
    let ctx = test_ctx();
    let env = SecureEnv::new(ontology.clone(), ctx.clone());

    assert!(Arc::ptr_eq(env.ontology(), &ontology));
    assert_eq!(env.security_ctx().org_id, ctx.org_id);
}

#[test]
fn local_env_new_stores_ontology() {
    let ontology = Arc::new(Ontology::new());
    let env = LocalEnv::local(ontology.clone());

    assert!(Arc::ptr_eq(env.ontology(), &ontology));
    assert!(
        env.security_ctx().admin,
        "local env must run as admin so admin_only fields stay visible in CLI tooling"
    );
}

#[test]
fn secure_env_has_ontology_returns_ref() {
    let env = env();
    let _ont: &Arc<Ontology> = env.ontology();
}

#[test]
fn secure_env_has_security_ctx_returns_ref() {
    let env = env();
    let _ctx: &SecurityContext = env.security_ctx();
}

// ═════════════════════════════════════════════════════════════════════════════
// PipelineState derive — from_* constructors
// ═════════════════════════════════════════════════════════════════════════════

#[test]
fn from_json_sets_json_only() {
    let state = QueryState::from_json("{}");
    assert!(state.json.is_some());
    assert!(state.input.is_none());
    assert!(state.node.is_none());
    assert!(state.result_ctx.is_none());
    assert!(state.output.is_none());
}

#[test]
fn from_input_sets_input_only() {
    let input: Input = serde_json::from_str(
        r#"{"query_type": "traversal", "node": {"id": "u", "entity": "User", "node_ids": [1]}, "limit": 10}"#,
    )
    .unwrap();
    let state = QueryState::from_input(input);
    assert!(state.json.is_none());
    assert!(state.input.is_some());
    assert!(state.node.is_none());
    assert!(state.result_ctx.is_none());
    assert!(state.output.is_none());
}

// ═════════════════════════════════════════════════════════════════════════════
// PipelineState derive — get/set/take/mut trait methods
// ═════════════════════════════════════════════════════════════════════════════

#[test]
fn get_on_populated_field_returns_ref() {
    let state = QueryState::from_json(r#"{"hello": "world"}"#);
    let json = state.json().unwrap();
    assert_eq!(json, r#"{"hello": "world"}"#);
}

#[test]
fn get_on_empty_field_returns_pipeline_invariant_error() {
    let state = QueryState::from_json("{}");
    let err = state.input().unwrap_err();
    match &err {
        QueryError::PipelineInvariant(msg) => {
            assert!(msg.contains("input"), "error should name the field: {msg}");
        }
        other => panic!("expected PipelineInvariant, got: {other}"),
    }
}

#[test]
fn set_overwrites_existing_value() {
    let mut state = QueryState::from_json("first");
    state.set_json("second".to_string());
    assert_eq!(state.json().unwrap(), "second");
}

#[test]
fn take_returns_value_and_clears_field() {
    let mut state = QueryState::from_json("take me");
    let taken = state.take_json().unwrap();
    assert_eq!(taken, "take me");
    assert!(state.json.is_none(), "field should be None after take");
}

#[test]
fn take_on_empty_field_returns_error() {
    let mut state = QueryState::from_json("{}");
    let err = state.take_input().unwrap_err();
    match &err {
        QueryError::PipelineInvariant(msg) => {
            assert!(msg.contains("input"), "error should name the field: {msg}");
        }
        other => panic!("expected PipelineInvariant, got: {other}"),
    }
}

#[test]
fn get_after_take_returns_error() {
    let mut state = QueryState::from_json("gone");
    let _ = state.take_json().unwrap();
    let err = state.json().unwrap_err();
    match &err {
        QueryError::PipelineInvariant(msg) => {
            assert!(msg.contains("json"), "error should name the field: {msg}");
        }
        other => panic!("expected PipelineInvariant, got: {other}"),
    }
}

#[test]
fn mut_accessor_allows_in_place_modification() {
    let mut state = QueryState::from_json("original");
    let json_mut = state.json_mut().unwrap();
    json_mut.push_str(" modified");
    assert_eq!(state.json().unwrap(), "original modified");
}

// ═════════════════════════════════════════════════════════════════════════════
// Seal types — generated by define_state_capabilities!
// ═════════════════════════════════════════════════════════════════════════════

#[test]
fn seal_json_drops_json_field() {
    let mut state = QueryState::from_json("sealed");
    SealJson.seal(&mut state);
    assert!(state.json.is_none());
}

#[test]
fn seal_input_drops_input_field() {
    let input: Input = serde_json::from_str(
        r#"{"query_type": "traversal", "node": {"id": "u", "entity": "User", "node_ids": [1]}, "limit": 10}"#,
    )
    .unwrap();
    let mut state = QueryState::from_input(input);
    SealInput.seal(&mut state);
    assert!(state.input.is_none());
}

#[test]
fn seal_node_drops_node_field() {
    let mut state = QueryState::from_json("{}");
    // node is already None — seal on None is a no-op (no panic)
    SealNode.seal(&mut state);
    assert!(state.node.is_none());
}

#[test]
fn seal_does_not_affect_other_fields() {
    let mut state = QueryState::from_json("keep me");
    let input: Input = serde_json::from_str(
        r#"{"query_type": "traversal", "node": {"id": "u", "entity": "User", "node_ids": [1]}, "limit": 10}"#,
    )
    .unwrap();
    state.set_input(input);

    SealJson.seal(&mut state);

    assert!(state.json.is_none(), "json should be sealed");
    assert!(state.input.is_some(), "input should be untouched");
}

#[test]
fn get_after_seal_returns_error() {
    let mut state = QueryState::from_json("sealed");
    SealJson.seal(&mut state);
    let err = state.json().unwrap_err();
    match &err {
        QueryError::PipelineInvariant(msg) => {
            assert!(msg.contains("json"), "error should name the field: {msg}");
        }
        other => panic!("expected PipelineInvariant, got: {other}"),
    }
}
